Hi,

I updated exceljs from 3.5 to 3.7 and I can't load a file from an input type file (with reactjs)
Here is a sample of code wich works in 3.5 but not in 3.7


``` javascript
import React from 'react'
import {useState} from 'react'
import ExcelJS from 'exceljs'

function App() {
  
  const [file, setFile] = useState({})
  
  function handleFormSubmit(e){
   
    loadFile().then(workbook => {
        console.log(workbook)
    })
    
    e.preventDefault()
    e.stopPropagation()
  }
  
  function loadFile(){
    return new Promise(function(resolve, reject){
      file.arrayBuffer().then(b => {
        let workbook = new ExcelJS.Workbook()
        workbook.xlsx.load(b).then(() => {
          resolve(workbook)
        })
      })
      .catch(e => reject(e))
    })
  }
  
  return (
    <div className="App">
      <form onSubmit={e => handleFormSubmit(e)}>
        <label>File : <input type="file" onChange={e => setFile(e.target.files[0])} /></label>
        <br />
        <input type="submit" value="Submit" />
      </form>
    </div>
    );
  }
  
 export default App
```


