Having the same issue. 

Works fine with `Buffer`s produced by Node's `fs.readFileSync`, but not in the browser with `Buffer.from(array_buffer)` where `ArrayBuffer` is produced by something like:

```typescript
export function readFileAsync(file: File) {
    return new Promise<ArrayBuffer>((resolve, reject) => {
        const reader = new FileReader()
        reader.onload = () => {
            if (reader.result instanceof ArrayBuffer) {
                resolve(reader.result)
            } else {
                reject(new Error('Result is not an ArrayBuffer'))
            }
        }
        reader.onerror = reject
        reader.onabort = reject
        reader.readAsArrayBuffer(file)
    })
}
```
